import { Data } from "ws";
import { SocketService } from "./services/socket-service";
export default abstract class DidClientBase {
    /**
     * WebSocket connection
     */
    protected ws: SocketService | null;
    /**
     * Map of subscriptions
     */
    protected subscriptions: Map<string, {
        resolve: (value: unknown) => void;
        reject: (reason?: unknown) => void;
    }>;
    constructor(ws?: SocketService | null);
    /**
     * Handle incoming WS messages
     * @param message
     */
    protected abstract handleWsMessage(message: Data): Promise<void>;
}
